syntax.postgresql:
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  status VARCHAR(20) DEFAULT 'pending' NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL,
  notes TEXT DEFAULT ''
);

-- Modify default on existing column
ALTER TABLE orders ALTER COLUMN status SET DEFAULT 'new';

